insert into app.subscription_version_action (
    subscription_id, product_id, product_version_id, action_type,
    action_status, change_type, version_note, handled_at
) values (
    #{subscriptionId}, #{productId}, #{productVersionId}, #{actionType},
    #{actionStatus}, #{changeType}, #{versionNote}, #{handledAt}
)

mapper.select:
select id, subscription_id, product_id, product_version_id, action_type, action_status, change_type, version_note, created_at, handled_at from app.subscription_version_action where action_status = 'PENDING' and subscription_id in
#{subscriptionId}
order by created_at desc, id desc
